\begin{equation}
\hat{R}^{AB}(\tau) = \int_0^\tau \left(\hat{X}^A(s) \frac{d\hat{P}_B(s)}{ds} - \hat{P}_B(s) \frac{d\hat{X}^A(s)}{ds}\right) \, ds \mod \mathcal{H}^{AB}
