    \end{equation}
    Units: [radians]

\item $\kappa_{ij}$: Coupling constant from the 7D cross-product table
    \begin{equation}
    \kappa_{ij} = \begin{cases}
    +1 & \text{for } (i,j) \in \{(x,y,z), (t_x,t_y,t_z), (x,t_y,z), \ldots\} \\
    -1 & \text{for } (i,j) \in \{(y,x,z), (t_y,t_x,t_z), (y,t_x,z), \ldots\} \\
